def compound_interest(principal, rate, years):
    # Return the final amount after compounding `rate` per period for `years`.
    return principal * (1 + rate) ** years


def split_evenly(total, parts):
    # Divide `total` into `parts` equal shares as a list of floats.
    if parts <= 0:
        raise ValueError("parts must be positive")
    share = total / parts
    return [share] * parts

class CheckoutError(Exception):
    """Raised when a checkout cannot be completed."""

    def __init__(self, message, code):
        super().__init__(message)
        self.code = code


def checkout(cart, balance):
    # cart: list of item prices (numbers). balance: available funds.
    if not cart:
        raise CheckoutError("cart is empty", code="empty_cart")
    total = sum(cart)
    if total > balance:
        raise CheckoutError(
            f"insufficient funds: need {total}, have {balance}",
            code="insufficient_funds",
        )
    return balance - total

import warnings


def normalize_scores(scores):
    # Clamp each score into [0, 100]. If any value is out of range, warn once
    # (UserWarning) that data was clamped, then return the clamped list.
    clamped = []
    out_of_range = 0
    for s in scores:
        if s < 0:
            clamped.append(0)
            out_of_range += 1
        elif s > 100:
            clamped.append(100)
            out_of_range += 1
        else:
            clamped.append(s)
    if out_of_range:
        warnings.warn(
            f"clamped {out_of_range} out-of-range score(s)",
            UserWarning,
        )
    return clamped

