def tally_votes(ballots):
    # ballots: iterable of candidate names (strings).
    # Return a dict mapping candidate -> vote count. Names are case-insensitive
    # and surrounding whitespace is ignored; blank/whitespace-only ballots are
    # skipped entirely.
    counts = {}
    for raw in ballots:
        name = raw.strip().lower()
        if not name:
            continue
        counts[name] = counts.get(name, 0) + 1
    return counts


def unique_words(text):
    # Return the set of distinct lowercase words in `text`, split on whitespace.
    return {word.lower() for word in text.split()}

