from solution import tally_votes, unique_words


def test_tally_counts_each_candidate():
    result = tally_votes(["ann", "bob", "ann"])
    # Comparing dicts directly gives a readable diff on failure.
    assert result == {"ann": 2, "bob": 1}


def test_tally_is_case_and_whitespace_insensitive():
    # Edge: "Ann", " ann " and "ann" are the same candidate.
    result = tally_votes(["Ann", " ann ", "ANN"])
    assert result == {"ann": 3}


def test_tally_skips_blank_ballots():
    # Tricky: empty and whitespace-only ballots must not create a "" key.
    result = tally_votes(["bob", "", "   ", "bob"])
    assert "" not in result
    assert result == {"bob": 2}


def test_tally_membership_and_subset():
    result = tally_votes(["x", "y", "z", "x"])
    assert "x" in result
    assert set(result) >= {"x", "y"}
    assert result["x"] == 2


def test_unique_words_returns_a_set():
    words = unique_words("the cat the dog")
    assert words == {"the", "cat", "dog"}


def test_unique_words_order_independent():
    # Tricky: a set has no order, so comparison must not depend on it; this
    # would fail if the function returned a list instead of a set.
    assert unique_words("b a c") == unique_words("c a b")
    assert isinstance(unique_words("a"), set)
